import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { UnboundedDarkEnergyFork, DisjointDarkMatterFork, type DarkMatterTaskResult } from './dark-fork-topology';
import { MeshEngine, createEngine } from './mesh-engine';
import { SchedulingMesh } from './scheduling-mesh';

describe('Dark Fork Topology', () => {
  let engine: MeshEngine;

  beforeEach(() => {
    engine = createEngine('proton', 3); // Create a simple 3-level mesh
  });

  afterEach(() => {
    vi.restoreAllMocks();
  });

  describe('UnboundedDarkEnergyFork', () => {
    it('should saturate the mesh asynchronously and unbounded', async () => {
      const darkEnergy = new UnboundedDarkEnergyFork(engine, 5); // 5ms delay per fork emit
      
      let invocationCount = 0;
      const testTask = async () => {
        invocationCount++;
        return 'expansion';
      };

      darkEnergy.start(testTask);
      expect(darkEnergy.isRunning()).toBe(true);

      // Wait briefly for un-halting expansion to fire a few times
      await new Promise(r => setTimeout(r, 60));
      
      darkEnergy.stop();
      expect(darkEnergy.isRunning()).toBe(false);

      // It should have fired at least a few times, saturating idle hubs
      expect(invocationCount).toBeGreaterThan(0);
    });
  });

  describe('DisjointDarkMatterFork', () => {
    let darkMatter: DisjointDarkMatterFork;

    beforeEach(() => {
      darkMatter = new DisjointDarkMatterFork(engine);
    });

    it('should be invisible to Gauge Observation (Race) when completely dark', async () => {
      // Create a task that resolves quickly
      const chargeTask = async () => 42;
      
      // Hub 0 is standard in a fresh mesh
      const forked = darkMatter.forkMatter(0, chargeTask);

      // A race over purely dark matter should theoretically return null 
      // because 100% of the nodes have gaugeObservationCoupling = 0
      const raceResult = await darkMatter.gaugeRace(forked);
      
      expect(raceResult).toBeNull();
    });

    it('should be structurally visible to Gravity Fold (Promise.allSettled) despite being dark', async () => {
      const chargeTask = async () => 42;
      const forked = darkMatter.forkMatter(0, chargeTask);

      const foldResult = await darkMatter.gravityFold(forked);
      
      // We proved earlier that Dark Matter has `chargeThirds ≠ 0` but `coupling = 0`.
      // Fold doesn't care about the coupling layer check. It accesses the raw array.
      expect(foldResult.hub).toBe(0);
      expect(foldResult.results.length).toBeGreaterThan(0);
      
      // By structure, it returns a DarkMatterTaskResult containing intrinsic charge
      const firstResult = foldResult.results[0].result as DarkMatterTaskResult<number>;
      expect(firstResult.intrinsicCharge).toBe(42);
      expect(firstResult.gaugeObservationCoupling).toBe(0);
    });
  });
});
